import { MuteState } from './mute-state';
import { RiskAssessmentSnapshot } from './risk-assessment-snapshot';
/**
 * The event of a security problem.
 */
export interface SecurityProblemEvent {
    /**
     * Metadata of the muted state of a security problem in relation to an event.
     */
    muteState?: MuteState;
    /**
     * The reason of the event creation.
     */
    reason?: 'ASSESSMENT_CHANGED' | 'SECURITY_PROBLEM_CREATED' | 'SECURITY_PROBLEM_MUTED' | 'SECURITY_PROBLEM_REOPENED' | 'SECURITY_PROBLEM_RESOLVED' | 'SECURITY_PROBLEM_UNMUTED' | 'VULNERABILITY_DISCONTINUED' | 'VULNERABILITY_ID_CHANGED';
    /**
     * A snapshot of the risk assessment of a security problem.
     */
    riskAssessmentSnapshot?: RiskAssessmentSnapshot;
    /**
     * The timestamp when the event occurred.
     */
    timestamp?: number;
}
